1	import { Context, Next } from 'hono';
2	import crypto from 'node:crypto';
3	
4	import { supabase } from '../lib/supabase.js';
5	import { OUTCOME_INGEST_WORKER_BYPASS_HEADER } from '../lib/outcome-ingest-queue.js';
6	
7	const DEFAULT_WINDOW_MS = 60_000;
8	const DEFAULT_MAX_REQUESTS = 300;
9	const DEFAULT_FAIL_OPEN = true;
10	
11	function readPositiveInt(value: string | undefined, fallback: number): number {
12	    const parsed = Number.parseInt(value ?? '', 10);
13	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
14	    return parsed;
15	}
16	
17	function getWindowMs(): number {
18	    return readPositiveInt(process.env.RATE_LIMIT_WINDOW_MS, DEFAULT_WINDOW_MS);
19	}
20	
21	function getMaxRequests(): number {
22	    return readPositiveInt(process.env.RATE_LIMIT_MAX, DEFAULT_MAX_REQUESTS);
23	}
24	
25	function readBoolean(value: string | undefined, fallback: boolean): boolean {
26	    if (!value) return fallback;
27	    const normalized = value.trim().toLowerCase();
28	    if (['1', 'true', 'yes', 'on'].includes(normalized)) return true;
29	    if (['0', 'false', 'no', 'off'].includes(normalized)) return false;
30	    return fallback;
31	}
32	
33	function shouldFailOpen(): boolean {
34	    return readBoolean(process.env.RATE_LIMIT_FAIL_OPEN, DEFAULT_FAIL_OPEN);
35	}
36	
37	function normalizeTier(value: unknown): string {
38	    const normalized = String(value ?? '').trim().toLowerCase();
39	    if (normalized === 'free' || normalized === 'pro' || normalized === 'enterprise') {
40	        return normalized;
41	    }
42	    return 'pro';
43	}
44	
45	function buildBucketKey(customerId: string): string {
46	    return crypto
47	        .createHash('sha256')
48	        .update(`customer:${customerId}`)
49	        .digest('hex');
50	}
51	
52	interface ConsumeRateLimitRow {
53	    allowed?: boolean;
54	    retry_after_ms?: number;
55	}
56	
57	async function consumeRateLimitBucket(params: {
58	    customerId: string;
59	    customerTier: string;
60	    windowMs: number;
61	    maxRequests: number;
62	}): Promise<{ allowed: boolean; retryAfterMs: number }> {
63	    const { data, error } = await supabase.rpc('consume_rate_limit_bucket', {
64	        p_bucket_key: buildBucketKey(params.customerId),
65	        p_window_ms: params.windowMs,
66	        p_max_requests: params.maxRequests,
67	        p_tier: params.customerTier,
68	    });
69	
70	    if (error) {
71	        throw new Error(error.message);
72	    }
73	
74	    const first = Array.isArray(data)
75	        ? (data[0] as ConsumeRateLimitRow | undefined)
76	        : (data as ConsumeRateLimitRow | null);
77	
78	    if (!first || typeof first.allowed !== 'boolean') {
79	        throw new Error('Rate limiter RPC returned invalid payload');
80	    }
81	
82	    return {
83	        allowed: first.allowed,
84	        retryAfterMs: Math.max(0, Number(first.retry_after_ms ?? 0)),
85	    };
86	}
87	
88	export function __resetRateLimitStateForTests(): void {
89	    // no-op: DB-backed limiter has no in-process bucket state.
90	}
91	
92	export const rateLimitMiddleware = async (c: Context, next: Next): Promise<Response | void> => {
93	    // Internal Queue Loopback natively bypasses rate limiting, because the initial external request
94	    // that populated the array was already organically authenticated and rate-limited.
95	    if ((c.req.header(OUTCOME_INGEST_WORKER_BYPASS_HEADER) ?? '').trim() === '1') {
96	        await next();
97	        return;
98	    }
99	
100	    const customerId = c.get('customer_id') as string | undefined;
101	    const customerTier = normalizeTier(c.get('customer_tier') as string | undefined);
102	
103	    // Auth middleware handles missing customer context.
104	    if (!customerId) {
105	        await next();
106	        return;
107	    }
108	
109	    const windowMs = getWindowMs();
110	    const maxRequests = getMaxRequests();
111	
112	    try {
113	        const consumeResult = await consumeRateLimitBucket({
114	            customerId,
115	            customerTier,
116	            windowMs,
117	            maxRequests,
118	        });
119	
120	        if (consumeResult.allowed) {
121	            await next();
122	            return;
123	        }
124	
125	        const retryAfterMs = consumeResult.retryAfterMs > 0
126	            ? consumeResult.retryAfterMs
127	            : windowMs;
128	        const retryAfterSeconds = Math.max(1, Math.ceil(retryAfterMs / 1000));
129	
130	        c.header('Retry-After', String(retryAfterSeconds));
131	        return c.json(
132	            {
133	                error: 'RATE_LIMIT_EXCEEDED',
134	                message: `Too many requests. Limit: ${maxRequests}/min per customer.`,
135	                retry_after_ms: retryAfterMs,
136	            },
137	            429
138	        );
139	    } catch (err: any) {
140	        if (shouldFailOpen()) {
141	            console.warn('[rate-limit] backend unavailable, fail-open enabled:', err?.message ?? 'unknown error');
142	            await next();
143	            return;
144	        }
145	
146	        return c.json(
147	            {
148	                error: 'RATE_LIMIT_UNAVAILABLE',
149	                message: 'Rate limiter is temporarily unavailable.',
150	            },
151	            503,
152	        );
153	    }
154	};
