1	import { describe, it, expect, vi, beforeEach } from 'vitest';
2	
3	describe('Context Drift Detection', () => {
4	    // We will extract and test the function locally
5	    let sbMock: any;
6	    let insertMock: any;
7	
8	    beforeEach(() => {
9	        insertMock = vi.fn().mockResolvedValue({ error: null });
10	
11	        // Setup default mock responses
12	        sbMock = {
13	            from: vi.fn((table: string) => {
14	                const chain: any = {
15	                    select: vi.fn().mockReturnThis(),
16	                    eq: vi.fn().mockReturnThis(),
17	                    limit: vi.fn().mockReturnThis(),
18	                    gte: vi.fn().mockReturnThis(),
19	                    maybeSingle: vi.fn().mockResolvedValue({ data: null, error: null }),
20	                    insert: insertMock
21	                };
22	                return chain;
23	            })
24	        };
25	    });
26	
27	    // Dummy version of detectContextDrift capturing the logic changes
28	    async function detectContextDrift(
29	        sb: any,
30	        customerId: string,
31	        contextType: string,
32	        agentId: string
33	    ): Promise<void> {
34	        const { data: existingContext } = await sb
35	            .from('dim_contexts')
36	            .select('context_id')
37	            .eq('issue_type', contextType)
38	            .limit(1)
39	            .maybeSingle();
40	
41	        if (existingContext) {
42	            const { count } = await sb
43	                .from('fact_outcomes')
44	                .select('outcome_id', { count: 'exact', head: true })
45	                .eq('customer_id', customerId)
46	                .eq('context_id', existingContext.context_id);
47	
48	            if ((count ?? 0) > 0) return; // Not new — has history
49	        }
50	
51	        const { data: recentAlert } = await sb
