1	import { supabase } from './supabase.js';
2	import { writeCounterfactuals } from './ips-engine.js';
3	import { upsertSequence, closeSequence } from './sequence-tracker.js';
4	import { backpropagateReward } from './reward-backprop.js';
5	import { invalidateCache } from './scoring.js';
6	import { predictDrift } from './predictive-drift.js';
7	import type { SupabaseClient } from '@supabase/supabase-js';
8	
9	type TrustLifecycleStatus = 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new';
10	const PROTECTED_TRUST_STATUSES: readonly TrustLifecycleStatus[] = ['sandbox', 'suspended'];
11	
12	function isProtectedTrustStatus(status: string | null | undefined): status is TrustLifecycleStatus {
13	    return typeof status === 'string' && PROTECTED_TRUST_STATUSES.includes(status as TrustLifecycleStatus);
14	}
15	
16	function shouldPreserveProtectedStatus(
17	    currentStatus: string | null | undefined,
18	    nextStatus: string,
19	): boolean {
20	    // Suspended is sticky until explicit manual reinstatement.
21	    if (currentStatus === 'suspended') {
22	        return nextStatus !== 'suspended';
23	    }
24	
25	    // Sandbox can escalate to suspended automatically, but cannot auto-upgrade
26	    // back into probation/trusted without an explicit operator action.
27	    if (currentStatus === 'sandbox') {
28	        return nextStatus === 'probation' || nextStatus === 'trusted' || nextStatus === 'new';
29	    }
30	
31	    return false;
32	}
33	
34	// ── Shared Types ──
35	export interface OrchestratorParams {
36	    agentId: string;
37	    customerId: string;
38	    outcomeId: string;
39	    actionId: string;
40	    actionName: string;
41	    contextId: string;
42	    issueType: string;
43	    finalSuccess: boolean;
44	    finalOutcomeScore: number | null;
45	    responseMs?: number | null;
46	    episodeId?: string;
47	    businessOutcome?: string;
48	    errorCode?: string | null;
49	    decisionId?: string;
50	    decisionRecord?: any;
51	    signalConfidence?: number | null;
52	    /**
53	     * When true, the trust-update task is skipped entirely.
54	     * Set by the import route — imported historical rows must never
55	     * affect agent trust scores (trust only reflects live SDK signal).
56	     */
57	    skipTrust?: boolean;
58	}
59	
60	// ── Orchestrator Main Entrypoint ──
61	export async function orchestrateOutcome(params: OrchestratorParams): Promise<void> {
62	
63	    async function taskTrustUpdate() {
64	        // IMPORT GUARD: imported historical rows must never update agent trust.
65	        // Trust reflects live SDK signal only. skipTrust is set by the import route.
66	        if (params.skipTrust === true) return;
67	        await updateAgentTrust(params.agentId, params.customerId, params.finalSuccess,
68	            params.actionName, params.signalConfidence ?? null);
69	    }
70	
71	    async function taskContextDrift() {
72	        await detectContextDrift(supabase, params.customerId, params.issueType, params.agentId);
73	    }
74	
75	    async function taskSilentFailure() {
76	        await detectSilentFailure(supabase, {
77	            outcome_id: params.outcomeId,
78	            customer_id: params.customerId,
79	            agent_id: params.agentId,
80	            action_id: params.actionId,
81	            action_name: params.actionName,
82	            success: params.finalSuccess,
83	            outcome_score: params.finalOutcomeScore,
84	            business_outcome: params.businessOutcome ?? null,
85	            error_code: params.errorCode ?? null,
86	        });
87	    }
88	
89	    async function taskCounterfactuals() {
90	        if (params.decisionRecord?.ranked_actions) {
91	            const outcomeScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
92	            await writeCounterfactuals({
93	                decisionId: params.decisionId!,
94	                realOutcomeId: params.outcomeId,
95	                realOutcomeScore: outcomeScore,
96	                chosenActionName: params.actionName,
97	                rankedActions: params.decisionRecord.ranked_actions,
98	                contextHash: params.decisionRecord.context_hash ?? '',
99	                episodePosition: params.decisionRecord.episode_position ?? 0,
100	            });
101	        }
102	    }
103	
104	    async function taskSequence() {
105	        if (params.episodeId) {
106	            await upsertSequence({
107	                episodeId: params.episodeId,
108	                agentId: params.agentId,
109	                customerId: params.customerId,
110	                contextHash: params.decisionRecord?.context_hash ?? `${params.contextId}:${params.issueType}`,
111	                actionName: params.actionName,
112	                responseMs: params.responseMs ?? undefined,
113	            });
114	
115	            if (params.businessOutcome === 'resolved' || params.businessOutcome === 'failed') {
116	                const finalScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
117	                await closeSequence({
118	                    episodeId: params.episodeId,
119	                    agentId: params.agentId,
120	                    customerId: params.customerId,
121	                    finalOutcome: finalScore,
122	                });
123	
124	                await backpropagateReward({
125	                    episode_id: params.episodeId,
126	                    customer_id: params.customerId,
127	                    final_outcome: finalScore,
128	                    gamma: 0.85,
129	                });
130	            }
131	        }
132	    }
133	
134	    async function taskLatencySpike(): Promise<void> {
135	        const { data: recentOutcomes } = await supabase
136	            .from('fact_outcomes')
137	            .select('response_time_ms')
138	            .eq('agent_id', params.agentId)
139	            .eq('action_id', params.actionId)
140	            .order('timestamp', { ascending: false })
141	            .limit(20);
142	
143	        if (!recentOutcomes || recentOutcomes.length < 5) return;
144	
145	        const current = recentOutcomes[0].response_time_ms;
146	        if (!current || current <= 0) return;
147	
148	        const baselineValues = recentOutcomes
149	            .slice(1, 16)
150	            .map((r) => r.response_time_ms)
151	            .filter((v): v is number => typeof v === 'number' && v > 0)
152	            .sort((a, b) => a - b);
153	
154	        if (baselineValues.length < 3) return;
155	
156	        const mid = Math.floor(baselineValues.length / 2);
157	        const median = baselineValues[mid]!;
158	
159	        // 3× multiplier + 1000ms absolute floor prevents false positives
160	        // (e.g. an action that normally takes 50ms spiking to 200ms is not worth alerting on)
161	        if (current <= median * 3 || current <= 1000) return;
162	
163	        // Deduplicate: skip if a latency_spike alert already exists for
164	        // this (customer_id, action_id) in the last hour
165	        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
166	        const { data: existing } = await supabase
167	            .from('degradation_alert_events')
168	            .select('id')
169	            .eq('customer_id', params.customerId)
170	            .eq('action_id', params.actionId)
171	            .eq('alert_type', 'latency_spike')
172	            .gte('created_at', oneHourAgo)
173	            .limit(1);
174	
175	        if (existing && existing.length > 0) return;
176	
177	        await supabase.from('degradation_alert_events').insert({
178	            customer_id: params.customerId,
179	            agent_id: params.agentId,
180	            action_id: params.actionId,
181	            alert_type: 'latency_spike',
182	            severity: 'warning',
183	            message:
184	                `Latency spike detected on action "${params.actionName}". ` +
185	                `Current response time: ${current}ms vs median baseline: ${median}ms ` +
186	                `(${(current / median).toFixed(1)}× normal).`,
187	        });
188	    }
189	
190	    async function taskCacheInvalidation() {
191	        // Invalidate only this customer/context score cache entry so the next
192	        // getScores() call reads fresh data instead of serving a stale 5-min TTL entry.
193	        invalidateCache(params.customerId, params.contextId);
194	    }
195	
196	    async function taskPredictiveDrift(): Promise<void> {
197	        // Predictive drift only runs for live SDK outcomes, not imports.
198	        if (params.skipTrust === true) return;
199	        await predictDrift(
200	            params.actionId,
201	            params.customerId,
202	            params.agentId,
203	            params.actionName,
204	        );
205	    }
206	
207	    // Trust atomicity is guaranteed by the update_trust_and_audit() RPC (migration 062),
208	    // which writes both the trust score UPDATE and audit INSERT in one DB transaction.
209	    // Surfacing trust failures as HTTP 500 to agents is counterproductive — a trust DB
210	    // issue should not block outcome logging entirely. Run all tasks via allSettled.
211	    const results = await Promise.allSettled([
212	        taskTrustUpdate(),
213	        taskContextDrift(),
214	        taskSilentFailure(),
215	        taskCounterfactuals(),
216	        taskSequence(),
217	        taskLatencySpike(),
218	        taskCacheInvalidation(),
219	        taskPredictiveDrift(),
220	    ]);
221	
222	    const taskNames = [
223	        'trust-update',
224	        'context-drift',
225	        'silent-failure',
226	        'counterfactuals',
227	        'sequence',
228	        'latency-spike',
229	        'cache-invalidation',
230	        'predictive-drift',
231	    ];
232	
233	    const criticalTaskFailures: string[] = [];
234	
235	    results.forEach((result, index) => {
236	        if (result.status === 'rejected') {
237	            const taskName = taskNames[index];
238	            const errorMessage = (result.reason as Error)?.message ?? String(result.reason);
239	
240	            console.error(`[orchestrator:${taskName}] failed`, {
241	                error: errorMessage,
242	                outcomeId: params.outcomeId,
243	                agentId: params.agentId,
244	            });
245	
246	            if (taskName === 'trust-update' || taskName === 'counterfactuals') {
247	                criticalTaskFailures.push(
248	                    `${taskName} failed for outcome_id=${params.outcomeId} agent_id=${params.agentId}: ${errorMessage}`
249	                );
250	            }
251	        }
252	    });
253	
254	    if (criticalTaskFailures.length > 0) {
255	        void Promise.resolve(supabase.from('degradation_alert_events').insert({
256	            customer_id: params.customerId,
257	            agent_id: params.agentId,
258	            alert_type: 'orchestrator_failure',
259	            severity: 'critical',
260	            message: criticalTaskFailures.join(' | '),
261	        })).catch(() => { });
262	    }
263	
264	    // Non-blocking: refresh trust cache row for dashboard reads.
265	    // Trust score/status authority is updateAgentTrust() via update_trust_and_audit RPC.
266	    // IMPORT GUARD: skip for imported rows — trust reflects SDK signal only.
267	    if (params.skipTrust !== true) {
268	        refreshLiveTrustCache(params.agentId).catch((err) =>
269	            console.warn('[orchestrator] refreshLiveTrustCache failed:', (err as Error).message)
270	        );
271	    }
272	}
273	
274	// ── Live Trust Cache Refresh (fire-and-forget) ──
275	// Read-only for existing rows: never recomputes trust score/status.
276	// Bootstrap-only write: inserts a neutral row if the trigger-minted row is missing.
277	async function refreshLiveTrustCache(
278	    agentId: string,
279	): Promise<void> {
280	    const { data: trustRow, error } = await supabase
281	        .from('agent_trust_scores')
282	        .select('agent_id, trust_score, trust_status, total_decisions, consecutive_failures')
283	        .eq('agent_id', agentId)
284	        .maybeSingle();
285	
286	    if (error) {
287	        console.warn('[trust] refreshLiveTrustCache: failed to read agent_trust_scores:', error.message);
288	        return;
289	    }
290	
291	    if (trustRow) {
292	        return;
293	    }
294	
295	    const { error: bootstrapError } = await supabase
296	        .from('agent_trust_scores')
297	        .upsert({
298	            agent_id: agentId,
299	            trust_score: null,
300	            trust_status: 'new',
301	            consecutive_failures: 0,
302	            total_decisions: 0,
303	            updated_at: new Date().toISOString(),
304	        }, { onConflict: 'agent_id' });
305	
306	    if (bootstrapError) {
307	        console.warn(
308	            '[trust] refreshLiveTrustCache: failed to bootstrap missing trust row:',
309	            bootstrapError.message,
310	        );
311	    }
312	}
313	
314	// ── Trust Snapshot (fire-and-forget) ──────────────────────────
315	async function snapshotTrust(
316	    agentId: string,
317	    trust: { trust_score: number; trust_status: string; consecutive_failures: number },
318	    reason: 'pre_failure' | 'pre_incident' | 'manual',
319	    incidentId?: string,
320	): Promise<void> {
321	    await supabase.from('agent_trust_snapshots').insert({
322	        agent_id: agentId,
323	        trust_score: trust.trust_score,
324	        trust_status: trust.trust_status,
325	        consecutive_failures: trust.consecutive_failures,
326	        snapshot_reason: reason,
327	        incident_id: incidentId ?? null,
328	    });
329	}
330	
331	/**
332	 * Updates agent trust score using exponential smoothing.
333	 *
334	 * Formula:
335	 *   On success: new_score = min(score × 1.03, 1.0)
336	 *               consecutive_failures reset to 0
337	 *   On failure: new_score = score × (0.9 ^ consecutive_failures)
338	 *               consecutive_failures incremented
339	 *
340	 * Status thresholds:
341	 *   score >= 0.6                       → trusted
342	 *   score 0.3–0.6                      → probation
343	 *   score 0.1–0.3 OR failures >= 5     → sandbox
344	 *   score < 0.1  OR failures >= 10     → suspended
345	 *
346	 * Cold-start prior: 0.70 (set on first DB insert by account-setup trigger).
347	 * First real outcome moves score to ~0.721 (success) or ~0.567 (failure).
348	 *
349	 * Note: scoring.ts uses a separate Bayesian (Laplace) smoothing formula for
350	 * composite action scores (computeCompositeScore). These are independent calculations.
351	 * This function uses exponential smoothing only.
352	 */
353	async function updateAgentTrust(
354	    agentId: string,
355	    customerId: string,
356	    success: boolean,
357	    actionName?: string,
358	    signalConfidence?: number | null,
359	): Promise<void> {
360	    const { data: trust } = await supabase
361	        .from('agent_trust_scores')
362	        .select('trust_id, trust_score, total_decisions, correct_decisions, consecutive_failures, trust_status, suspension_reason')
363	        .eq('agent_id', agentId)
364	        .maybeSingle();
365	
366	    if (!trust) {
367	        // The fn_init_agent_trust() trigger (migration 058) should
368	        // have created this row. If it's missing, throw so the
369	        // orchestrator's allSettled logs a [trust-update] error.
370	        // Do NOT silently return - a missing row is a data integrity issue.
371	        throw new Error(
372	            `[trust] No agent_trust_scores row for agent_id=${agentId}. ` +
373	            `Trigger fn_init_agent_trust may have failed at agent creation.`
374	        );
375	    }
376	
377	    const currentScore = typeof trust.trust_score === 'number' ? trust.trust_score : 0.7;
378	    const currentTotalDecisions = typeof trust.total_decisions === 'number' ? trust.total_decisions : 0;
379	    const currentCorrectDecisions = typeof trust.correct_decisions === 'number' ? trust.correct_decisions : 0;
380	    const currentFailures = typeof trust.consecutive_failures === 'number' ? trust.consecutive_failures : 0;
381	    const currentStatus = typeof trust.trust_status === 'string' ? trust.trust_status : 'trusted';
382	    const currentSuspensionReason = typeof trust.suspension_reason === 'string' ? trust.suspension_reason : null;
383	
384	    // Always capture old values before any mutation.
385	    // These are written to every audit row so the dashboard can show
386	    // the score delta for each event in the Trust History timeline.
387	    const oldScore = currentScore;
388	    const oldStatus = currentStatus;
389	
390	    let newScore: number;
391	    let newFailures: number;
392	    let newCorrect = currentCorrectDecisions;
393	
394	    if (success) {
395	        newFailures = 0;
396	        newCorrect += 1;
397	        // ── Phase 1: Signal confidence weighting ──────────────
398	        // High-confidence signals (e.g. Stripe webhooks, explicit SDK)
399	        // contribute the full 3% growth. Low-confidence signals (e.g.
400	        // LLM evaluation at 0.3) contribute proportionally less.
401	        // When signalConfidence is null/1.0 → 1 + 0.03*1.0 = 1.03 (unchanged).
402	        const confidence = signalConfidence ?? 1.0;
403	        newScore = Math.min(currentScore * (1 + 0.03 * confidence), 1.0);
404	    } else {
405	        // ── Coordinated Failure Interlock ──────────────────────
406	        // Check if this failure is infrastructure-attributed before
407	        // applying decay. detect_coordinated_failures() looks for 3+
408	        // agents failing the same action within the last 5 minutes.
409	        let isInfrastructureFailure = false;
410	        if (actionName) {
411	            try {
412	                const { data: coordFailures, error: coordError } = await supabase.rpc('detect_coordinated_failures', {
413	                    window_minutes: 5,
414	                    min_agent_count: 3,
415	                });
416	                if (coordError) throw new Error(coordError.message);
417	                if (coordFailures && Array.isArray(coordFailures)) {
418	                    isInfrastructureFailure = coordFailures.some(
419	                        (row: { action_name: string }) => row.action_name === actionName
420	                    );
421	                }
422	            } catch (err) {
423	                // Coordination check failed — proceed with normal decay (fail safe)
424	                console.warn('[trust] Coordinated failure check failed:', (err as Error).message);
425	            }
426	        }
427	
428	        if (isInfrastructureFailure) {
429	            snapshotTrust(agentId, trust, 'pre_incident', `coordinated:${actionName ?? 'unknown'}`).catch(() => { });
430	
431	            const { error: auditError } = await supabase.from('agent_trust_audit').insert({
432	                agent_id: agentId,
433	                customer_id: customerId,
434	                event_type: 'failure_excluded_infrastructure',
435	                old_score: oldScore,
436	                new_score: oldScore,        // score unchanged — frozen
437	                old_status: oldStatus,
438	                new_status: oldStatus,      // status unchanged — frozen
439	                reason: `Failure excluded: coordinated infrastructure failure detected on action "${actionName}". Trust score frozen.`,
440	            });
441	            if (auditError) {
442	                throw new Error(`[trust] failed to write audit event: ${auditError.message}`);
443	            }
444	
445	            await supabase.from('degradation_alert_events').insert({
446	                customer_id: customerId,
447	                agent_id: agentId,
448	                alert_type: 'coordinated_failure',
449	                severity: 'critical',
450	                message:
451	                    `Coordinated infrastructure failure detected on action "${actionName}". ` +
452	                    `3+ agents failed this action within 5 minutes. ` +
453	                    `Trust score frozen for affected agents.`,
454	            });
455	
456	            console.info('[trust] Failure excluded — coordinated infrastructure event', { agentId, actionName });
457	            return; // No trust modification
458	        }
459	
460	        // Normal agent-attributable failure: snapshot then decay
461	        snapshotTrust(agentId, trust, 'pre_failure').catch(() => { });
462	        newFailures = currentFailures + 1;
463	        newScore = currentScore * Math.pow(0.9, newFailures);
464	    }
465	
466	    let newStatus: string;
467	    let newSuspensionReason: string | null = null;
468	
469	    if (newScore < 0.1 || newFailures >= 10) {
470	        newStatus = 'suspended';
471	        newSuspensionReason = newScore < 0.1 ? 'trust_score_critically_low' : 'consecutive_failures_exceeded';
472	    } else if (newScore < 0.3 || newFailures >= 5) {
473	        newStatus = 'sandbox';
474	        newSuspensionReason = newFailures >= 5 ? 'consecutive_failures_exceeded' : null;
475	    } else if (newScore < 0.6) {
476	        newStatus = 'probation';
477	    } else {
478	        newStatus = 'trusted';
479	    }
480	
481	    if (shouldPreserveProtectedStatus(currentStatus, newStatus)) {
482	        console.warn(
483	            '[trust] updateAgentTrust: preserving protected status to avoid flip-flop',
484	            { agentId, currentStatus, computedStatus: newStatus }
485	        );
486	
487	        newStatus = currentStatus as TrustLifecycleStatus;
488	        if (newStatus === 'suspended') {
489	            newSuspensionReason = currentSuspensionReason ?? 'manual_reinstatement_required';
490	        } else if (newStatus === 'sandbox') {
491	            newSuspensionReason = currentSuspensionReason;
492	        }
493	    }
494	
495	    // ── ML-CHECK-2.1-B FIX: atomic trust UPDATE + audit INSERT via RPC ──
496	    // Previously: two separate supabase calls. If the audit INSERT failed,
497	    // trust score was already updated with no audit record (INVARIANT 7 violation).
498	    // Now: both ops execute inside one PL/pgSQL transaction (migration 052).
499	    // Either both succeed or both are rolled back.
500	    //
501	    // Reason format is intentional — agent.tsx parseActionFromReason()
502	    // relies on exactly these two patterns to extract the action name:
503	    //   "Outcome success via SDK: {actionName}"
504	    //   "Outcome failure recorded: {actionName}"
505	    // Status-change events append a transition note that
506	    // parseStatusLabel() in agent.tsx picks up separately.
507	
508	    const action = actionName?.trim() || 'unknown_action';
509	    const statusChanged = oldStatus !== newStatus;
510	
511	    const baseReason = success
512	        ? `Outcome success via SDK: ${action}`
513	        : `Outcome failure recorded: ${action}`;
514	
515	    const reason = statusChanged
516	        ? `${baseReason} | Trust recalibrated: ${oldStatus} → ${newStatus}`
517	        : baseReason;
518	
519	    const { error: rpcError } = await supabase.rpc('update_trust_and_audit', {
520	        p_agent_id: agentId,
521	        p_customer_id: customerId,
522	        p_trust_score: newScore,
523	        p_total_decisions: currentTotalDecisions + 1,
524	        p_correct_decisions: newCorrect,
525	        p_consecutive_failures: newFailures,
526	        p_trust_status: newStatus,
527	        p_suspension_reason: newSuspensionReason,
528	        p_updated_at: new Date().toISOString(),
529	        p_event_type: success ? 'success' : 'failure',
530	        p_old_score: oldScore,
531	        p_old_status: oldStatus,
532	        p_new_status: newStatus,
533	        p_performed_by: 'outcome-orchestrator',
534	        p_reason: reason,
535	    });
536	
537	    if (rpcError) {
538	        throw new Error(`[trust] atomic trust+audit update failed: ${rpcError.message}`);
539	    }
540	}
