543	// BEFORE: context lookup used only issue_type with no customer_id filter.
544	// This meant Customer A's contexts were matched against Customer B's
545	// outcomes, causing false "context drift" alerts across customers.
546	//
547	// AFTER: every query is scoped by customer_id. Each customer only
548	// sees their own contexts and their own outcomes.
549	async function detectContextDrift(
550	    sb: SupabaseClient,
551	    customerId: string,
552	    contextType: string,
553	    agentId: string,
554	): Promise<void> {
555	    const { data: existingContext } = await sb
556	        .from('dim_contexts')
557	        .select('context_id')
558	        .eq('customer_id', customerId)       // FIX: was missing — caused cross-customer matches
559	        .eq('issue_type', contextType)
560	        .limit(1)
561	        .maybeSingle();
562	
563	    if (existingContext) {
564	        const { count } = await sb
565	            .from('fact_outcomes')
566	            .select('outcome_id', { count: 'exact', head: true })
567	            .eq('customer_id', customerId)
568	            .eq('context_id', existingContext.context_id);
569	
570	        if ((count ?? 0) > 0) return;
571	    }
572	
573	    const { data: recentAlert } = await sb
574	        .from('degradation_alert_events')
575	        .select('alert_id')
576	        // TODO: Add (customer_id, alert_type, context_type) composite unique constraint
577	        // to degradation_alert_events once a context_type column is added (migration TBD).
578	        // Until then, message-based ilike dedup is the deduplication mechanism.
579	        .eq('customer_id', customerId)
580	        .eq('alert_type', 'context_drift')
581	        .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
582	        .ilike('message', `%"${contextType}"%`)
583	        .limit(1);
