587	    await sb.from('degradation_alert_events').insert({
588	        customer_id: customerId,
589	        alert_type: 'context_drift',
590	        severity: 'warning',
591	        message: `New context type "${contextType}" encountered by agent ${agentId}. No prior outcomes for this customer. Cold-start protocol activated.`,
592	    });
593	}
