335	/**
336	 * Mark a queue row as failed. If max attempts reached, move to dead-letter.
337	 * Uses exponential backoff for retry scheduling.
338	 */
339	async function markFailed(ingressId: string, errorMessage: string, currentAttempts: number, maxAttempts: number): Promise<void> {
340	    const newAttempts = currentAttempts + 1;
341	    const isDead = newAttempts >= maxAttempts;
342	
343	    if (isDead) {
344	        const { error } = await supabase
345	            .from('queue_outcome_ingress')
346	            .update({
347	                status: 'dead',
348	                attempts: newAttempts,
349	                last_error: errorMessage.slice(0, 1000),
350	                completed_at: new Date().toISOString(),
351	                locked_by: null,
352	                locked_at: null,
353	            })
354	            .eq('ingress_id', ingressId);
355	
356	        if (error) {
357	            console.error('[durable-queue] markDead failed:', ingressId, error.message);
358	        } else {
359	            console.warn('[durable-queue] ☠️  Dead-lettered:', { ingress_id: ingressId, attempts: newAttempts, error: errorMessage.slice(0, 200) });
360	        }
361	        return;
362	    }
363	
364	    // Exponential backoff: 2^attempt seconds, capped at 60s, plus jitter
365	    const backoffMs = Math.min(60_000, 1000 * Math.pow(2, newAttempts)) + Math.floor(Math.random() * 1000);
366	    const nextAttemptAt = new Date(Date.now() + backoffMs).toISOString();
367	
368	    const { error } = await supabase
369	        .from('queue_outcome_ingress')
370	        .update({
371	            status: 'failed',
372	            attempts: newAttempts,
373	            last_error: errorMessage.slice(0, 1000),
374	            next_attempt_at: nextAttemptAt,
375	            locked_by: null,
376	            locked_at: null,
377	        })
378	        .eq('ingress_id', ingressId);
379	
380	    if (error) {
381	        console.error('[durable-queue] markFailed failed:', ingressId, error.message);
382	    }
383	}
