385	/**
386	 * Process a single queue row by directly invoking ingestOutcome().
387	 * No HTTP loopback. No middleware re-entry. No auth/rate-limit fragility.
388	 */
389	async function processDurableItem(row: QueueRow): Promise<void> {
390	    const payload = row.payload as Record<string, unknown>;
391	
392	    // Build the NormalizedOutcomeRow from the stored payload.
393	    // The payload is the full parsed SDK body — extract every field
394	    // that ingestOutcome() can consume to maintain parity with sync path.
395	    const verifierSignal = typeof payload.verifier_signal === 'object' && payload.verifier_signal !== null
396	        ? payload.verifier_signal as Record<string, unknown>
397	        : null;
398	
399	    const normalizedRow: NormalizedOutcomeRow = {
400	        agent_id: row.agent_id,
401	        action_name: (payload.action_name as string) ?? 'unknown_action',
402	        issue_type: (payload.issue_type as string) ?? 'unknown',
403	        success: payload.success === true,
404	        outcome_score: typeof payload.outcome_score === 'number' ? payload.outcome_score : undefined,
405	        business_outcome: (payload.business_outcome as string) ?? undefined,
406	        session_id: (payload.session_id as string) ?? undefined,
407	        response_time_ms: typeof payload.response_time_ms === 'number' ? payload.response_time_ms : undefined,
408	        feedback_signal: (payload.feedback_signal as string) ?? undefined,
409	        decision_id: (payload.decision_id as string) ?? undefined,
410	        episode_id: (payload.episode_id as string) ?? undefined,
411	        task_name: (payload.task_name as string) ?? undefined,
412	        raw_context: typeof payload.raw_context === 'object' && payload.raw_context !== null
413	            ? payload.raw_context as Record<string, unknown>
414	            : undefined,
415	        error_code: (payload.error_code as string) ?? undefined,
416	        error_message: (payload.error_message as string) ?? undefined,
417	        idempotency_key: (payload.idempotency_key as string) ?? undefined,
418	        environment: (payload.environment as string) ?? undefined,
419	        customer_tier: (payload.customer_tier as string) ?? undefined,
420	        // Verifier signal — SDK sends as nested { source, value }
421	        verifier_source: (verifierSignal?.source as string) ?? undefined,
422	        verifier_value: verifierSignal?.value as string | number | boolean | undefined ?? undefined,
423	        // Task mapping metadata (parser-provided)
424	        task_mapping_confidence: typeof payload.task_mapping_confidence === 'number' ? payload.task_mapping_confidence : undefined,
425	        task_mapping_tier: (payload.task_mapping_tier as string) ?? undefined,
426	        // Signal chain fields
427	        backprop_episode_id: (payload.backprop_episode_id as string) ?? undefined,
428	        signal_source: (payload.signal_source as any) ?? undefined,
429	        signal_confidence: typeof payload.signal_confidence === 'number' ? payload.signal_confidence : undefined,
430	        signal_depth: typeof payload.signal_depth === 'number' ? payload.signal_depth : undefined,
431	        signal_pending: typeof payload.signal_pending === 'boolean' ? payload.signal_pending : undefined,
432	        cross_event_status: (payload.cross_event_status as any) ?? undefined,
433	        // Retry chain fields
434	        retry_chain_id: (payload.retry_chain_id as string) ?? undefined,
435	        retry_attempt: typeof payload.retry_attempt === 'number' ? payload.retry_attempt : undefined,
436	        cross_event_attempt_count: typeof payload.cross_event_attempt_count === 'number' ? payload.cross_event_attempt_count : undefined,
437	        canonical_outcome_id: (payload.canonical_outcome_id as string) ?? undefined,
438	        pending_registration_id: (payload.pending_registration_id as string) ?? undefined,
439	        // Execution status fields
440	        execution_status: (payload.execution_status as string) ?? undefined,
441	        failure_reason_code: (payload.failure_reason_code as string) ?? undefined,
442	        failure_stage: (payload.failure_stage as string) ?? undefined,
443	        status_origin: (payload.status_origin as string) ?? undefined,
444	        // Resource cost fields
445	        resource_cost_units: typeof payload.resource_cost_units === 'number' ? payload.resource_cost_units : undefined,
446	        resource_cost_type: (payload.resource_cost_type as any) ?? undefined,
447	    };
448	
449	    const result = await ingestOutcome(normalizedRow, row.customer_id, {
450	        skipTrustUpdate: false,
451	        ingestionSource: 'sdk',
452	    });
453	
454	    // Fire-and-forget side effects — parity with sync path.
455	    // These must never throw or block the queue worker.
456	    refreshTaskAggregation(row.customer_id).catch(() => {});
457	    if (result.actionId) {
458	        checkRecommendationRegression(
459	            row.customer_id,
460	            row.agent_id,
461	            result.actionId,
462	            normalizedRow.action_name,
463	            normalizedRow.task_name ?? null,
464	            normalizedRow.success,
465	        ).catch(() => {});
466	    }
467	}
