469	let durableWorkerTimer: ReturnType<typeof setInterval> | null = null;
470	
471	// App-level purge — replaces pg_cron on Supabase free tier
472	let lastPurgeAt = 0;
473	const PURGE_INTERVAL_MS = 60 * 60 * 1000; // 1 hour
474	
475	async function maybePurgeSucceeded(): Promise<void> {
476	    const now = Date.now();
477	    if (now - lastPurgeAt < PURGE_INTERVAL_MS) return;
478	    lastPurgeAt = now;
479	
480	    try {
481	        const { error } = await supabase.rpc('purge_succeeded_queue_ingress' as any);
482	        if (error) {
483	            // RPC might not exist yet — fall back to direct delete
484	            const { error: deleteErr } = await supabase
485	                .from('queue_outcome_ingress')
486	                .delete()
487	                .eq('status', 'succeeded')
488	                .lt('completed_at', new Date(now - 24 * 60 * 60 * 1000).toISOString());
489	
490	            if (deleteErr) {
491	                console.warn('[durable-queue] Purge fallback failed:', deleteErr.message);
492	            } else {
493	                console.log('[durable-queue] Purged succeeded rows (>24h) via direct delete');
494	            }
495	        } else {
496	            console.log('[durable-queue] Purged succeeded rows (>24h) via RPC');
497	        }
498	    } catch {
499	        // Best-effort — never block the worker
500	    }
501	}
