559	/**
560	 * Get queue health metrics for /health/deep endpoint.
561	 */
562	export async function getDurableQueueHealth(): Promise<{
563	    pending: number;
564	    failed: number;
565	    dead: number;
566	    processing: number;
567	    oldest_pending_age_seconds: number | null;
568	}> {
569	    try {
570	        const [pendingRes, failedRes, deadRes, processingRes, oldestRes] = await Promise.all([
571	            supabase.from('queue_outcome_ingress').select('ingress_id', { count: 'exact', head: true }).eq('status', 'pending'),
572	            supabase.from('queue_outcome_ingress').select('ingress_id', { count: 'exact', head: true }).eq('status', 'failed'),
573	            supabase.from('queue_outcome_ingress').select('ingress_id', { count: 'exact', head: true }).eq('status', 'dead'),
574	            supabase.from('queue_outcome_ingress').select('ingress_id', { count: 'exact', head: true }).eq('status', 'processing'),
575	            supabase.from('queue_outcome_ingress').select('created_at').eq('status', 'pending').order('created_at', { ascending: true }).limit(1),
576	        ]);
577	
578	        let oldestAge: number | null = null;
579	        if (oldestRes.data && oldestRes.data.length > 0) {
580	            const created = new Date((oldestRes.data[0] as any).created_at).getTime();
581	            oldestAge = Math.round((Date.now() - created) / 1000);
582	        }
583	
584	        return {
585	            pending: pendingRes.count ?? 0,
586	            failed: failedRes.count ?? 0,
587	            dead: deadRes.count ?? 0,
588	            processing: processingRes.count ?? 0,
589	            oldest_pending_age_seconds: oldestAge,
590	        };
591	    } catch {
592	        return { pending: -1, failed: -1, dead: -1, processing: -1, oldest_pending_age_seconds: null };
593	    }
594	}
